/**
 * Context Exhaustion Warner — UserPromptSubmit Hook
 *
 * Reads context window usage percentage from a temp file written by the
 * StatusLine bridge (statusline-context-writer.sh) and injects tiered
 * warnings into Claude's context via additionalContext.
 *
 * Tiers (descending — first match wins):
 *   90%+ CRITICAL — commit now, session ending
 *   80%+ WARNING  — wrap up, commit soon
 *   70%+ NOTICE   — save progress, consider committing
 *
 * Escalation-only: each tier warns once per session. Warnings reset
 * when usage drops below 70% (e.g., after /compact or /clear).
 *
 * Bridge pattern:
 *   StatusLine (stdin JSON) → {tmpdir}/ork-ctx-pct-{session_id}.txt → this hook
 *
 * CC 2.1.9 Compliant: Uses hookSpecificOutput.additionalContext
 */

import { existsSync, readFileSync } from 'node:fs';
import { join } from 'node:path';
import type { HookInput, HookResult } from '../types.js';
import { logHook, outputSilentSuccess, getSessionId } from '../lib/common.js';
import { getTempDir } from '../lib/paths.js';
import { sanitizeSessionId } from '../lib/sanitize-shell.js';

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

interface WarnTier {
  pct: number;
  level: 'NOTICE' | 'WARNING' | 'CRITICAL';
  message: string;
}

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

/**
 * Warning tiers sorted descending so first match is the highest applicable tier.
 */
const TIERS: WarnTier[] = [
  {
    pct: 90,
    level: 'CRITICAL',
    message:
      'Context window is 90%+ full. Auto-compaction is imminent. Commit your current work NOW and create a handoff. Run /ork:commit then consider stopping this session.',
  },
  {
    pct: 80,
    level: 'WARNING',
    message:
      'Context window is 80%+ full. Start wrapping up your current task. Commit intermediate progress and consider creating a handoff soon.',
  },
  {
    pct: 70,
    level: 'NOTICE',
    message:
      'Context window is 70%+ full. Consider saving your progress. You can commit with /ork:commit to preserve work before context compaction.',
  },
];

// ---------------------------------------------------------------------------
// Module state — tracks which tiers have already been warned this session
// ---------------------------------------------------------------------------

let highestWarnedPct = 0;

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function getContextPctFilePath(sessionId: string): string {
  const safeId = sanitizeSessionId(sessionId);
  if (!safeId) return '';
  return join(getTempDir(), `ork-ctx-pct-${safeId}.txt`);
}

function readContextPercentage(sessionId: string): number | null {
  const filePath = getContextPctFilePath(sessionId);

  if (!filePath || !existsSync(filePath)) {
    return null;
  }

  try {
    const content = readFileSync(filePath, 'utf8').trim();
    const pct = Math.round(parseFloat(content));

    if (Number.isNaN(pct) || pct < 0 || pct > 100) {
      return null;
    }

    return pct;
  } catch {
    return null;
  }
}

// ---------------------------------------------------------------------------
// Hook Implementation
// ---------------------------------------------------------------------------

export function contextExhaustionWarner(input: HookInput): HookResult {
  const sessionId = input.session_id || getSessionId();

  if (!sessionId) {
    return outputSilentSuccess();
  }

  const pct = readContextPercentage(sessionId);

  if (pct === null) {
    // No context data available yet (StatusLine hasn't written)
    return outputSilentSuccess();
  }

  // Reset if context dropped (after /compact or /clear)
  if (pct < 70) {
    if (highestWarnedPct > 0) {
      logHook('context-exhaustion-warner', `Context dropped to ${pct}%, resetting warnings`);
      highestWarnedPct = 0;
    }
    return outputSilentSuccess();
  }

  // Find the highest matching tier
  const matchingTier = TIERS.find(t => pct >= t.pct);

  if (!matchingTier) {
    return outputSilentSuccess();
  }

  // Only warn on ESCALATION (don't repeat same tier)
  if (matchingTier.pct <= highestWarnedPct) {
    return outputSilentSuccess();
  }

  // Escalate!
  highestWarnedPct = matchingTier.pct;
  logHook('context-exhaustion-warner', `Context at ${pct}% — ${matchingTier.level} warning`);

  return {
    continue: true,
    hookSpecificOutput: {
      additionalContext: `[Context ${matchingTier.level}] ${matchingTier.message} (Current usage: ${pct}%)`,
    },
  };
}

// ---------------------------------------------------------------------------
// Exports for testing
// ---------------------------------------------------------------------------

export { readContextPercentage, getContextPctFilePath, TIERS };

/**
 * Reset module state between tests.
 */
export function _resetForTesting(): void {
  highestWarnedPct = 0;
}
