/**
 * Frustration Detector — UserPromptSubmit Hook (Analytics Only)
 * Issue #1243: DX observability — detect frustration signals in user prompts.
 *
 * Privacy-first design:
 * - Logs ONLY a boolean signal (frustrated: true/false)
 * - NEVER logs the matched text, pattern, or surrounding context
 * - Cross-project analytics use hashed project IDs (irreversible)
 *
 * Performance: single compiled regex test, no LLM calls.
 * This hook does NOT modify Claude's behavior — analytics only.
 */

import type { HookInput, HookResult } from '../types.js';
import { outputSilentSuccess, logHook, getProjectDir } from '../lib/common.js';
import { appendAnalytics, hashProject, getTeamContext } from '../lib/analytics.js';

// =============================================================================
// CONSTANTS
// =============================================================================

const HOOK_NAME = 'frustration-detector';

/**
 * Frustration detection regex — adapted from CC's userPromptKeywords.ts.
 * Matches common swear/frustration patterns. Case-insensitive, word-bounded.
 *
 * Privacy: this regex is used ONLY for boolean detection.
 * The matched text is never captured, logged, or stored.
 */
const FRUSTRATION_PATTERN =
  /\b(wtf|wth|ffs|omfg|shit(?:ty|tiest)?|horrible|awful|piss(?:ed|ing)?\s*off|what the (?:fuck|hell)|fuck(?:ing)?\s*(?:broken|useless|terrible)|so frustrating|this sucks|damn it)\b/i;

/** Minimum prompt length to analyze — skip trivial inputs */
const MIN_PROMPT_LENGTH = 3;

// =============================================================================
// DETECTION
// =============================================================================

/**
 * Test whether a prompt contains frustration signals.
 * Returns boolean only — no match details are extracted or stored.
 */
export function detectFrustration(prompt: string): boolean {
  return FRUSTRATION_PATTERN.test(prompt);
}

// =============================================================================
// MAIN HOOK
// =============================================================================

/**
 * Frustration detector hook.
 *
 * Runs regex against the user prompt and logs a boolean signal
 * to cross-project analytics. Never produces context output.
 */
export function frustrationDetector(input: HookInput): HookResult {
  const prompt = input.prompt || '';

  // Skip empty or trivial prompts
  if (prompt.length < MIN_PROMPT_LENGTH) {
    return outputSilentSuccess();
  }

  // Skip slash commands (skill invocations, not natural language)
  if (prompt.startsWith('/')) {
    return outputSilentSuccess();
  }

  try {
    const frustrated = detectFrustration(prompt);

    // Log only the boolean signal — never the matched text
    if (frustrated) {
      logHook(HOOK_NAME, 'Frustration signal detected');

      // Cross-project analytics (Issue #459 pattern)
      // Privacy: only boolean + hashed project + timestamp
      appendAnalytics('dx-signals.jsonl', {
        ts: new Date().toISOString(),
        pid: hashProject(getProjectDir()),
        signal: 'frustration',
        value: true,
        ...getTeamContext(),
      });
    }
  } catch (error) {
    // Never crash the hook chain
    logHook(HOOK_NAME, `Error: ${error}`, 'warn');
  }

  return outputSilentSuccess();
}
